'use client'
import { useState } from 'react'

const categories = [
  { name: 'Main Dish', count: '86+ items', emoji: '🍔', color: '#fff3e0', active: false },
  { name: 'Break Fast', count: '12 items', emoji: '🥞', color: '#fce4ec', active: false },
  { name: 'Dessert', count: '48+ items', emoji: '🧁', color: '#f3e5f5', active: false },
  { name: 'Browse All', count: '255+ items', emoji: '🍽️', color: '#e8f5e9', active: true },
]

export default function Categories() {
  const [active, setActive] = useState(3)

  return (
    <section className="py-20" style={{background: '#f9f9f9'}}>
      <div className="max-w-6xl mx-auto px-6">
        <div className="text-center mb-12">
          <div className="section-label mb-3">CUSTOMER FAVORITES</div>
          <h2 className="section-title">Popular Categories</h2>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
          {categories.map((cat, i) => (
            <button
              key={cat.name}
              onClick={() => setActive(i)}
              className={`card-hover rounded-2xl p-6 text-center flex flex-col items-center gap-4 border-2 transition-all duration-300 ${
                active === i
                  ? 'border-green-400 bg-white shadow-xl scale-105'
                  : 'border-transparent bg-white shadow-md hover:border-green-200'
              }`}
            >
              <div
                className="w-20 h-20 rounded-2xl flex items-center justify-center text-4xl transition-transform duration-300"
                style={{
                  background: active === i ? 'var(--color-primary-light)' : cat.color,
                  transform: active === i ? 'scale(1.05)' : 'scale(1)'
                }}
              >
                {cat.emoji}
              </div>
              <div>
                <div className={`font-bold text-base mb-1 ${active === i ? 'text-green-600' : 'text-gray-800'}`}>
                  {cat.name}
                </div>
                <div className="text-sm text-gray-400">{cat.count}</div>
              </div>
              {active === i && (
                <div className="w-8 h-1 rounded-full" style={{background: 'var(--color-primary)'}} />
              )}
            </button>
          ))}
        </div>
      </div>
    </section>
  )
}
